class CentralizedLogger:
    def __init__(self, es_host="localhost", es_port=9200):
        self.es = Elasticsearch([f"{es_host}:{es_port}"])
        self.index_name = "logs"
        self._create_index()
        
    def _create_index(self):
        if not self.es.indices.exists(index=self.index_name):
            mapping = {
                "mappings": {
                    "properties": {
                        "timestamp": {"type": "date"},
                        "level": {"type": "keyword"},
                        "message": {"type": "text"},
                        "service": {"type": "keyword"},
                        "host": {"type": "keyword"},
                        "tags": {"type": "keyword"}
                    }
                }
            }
            self.es.indices.create(index=self.index_name, body=mapping)
    
    def log(self, level, message, service="unknown", host="localhost", tags=None):
        log_entry = {
            "timestamp": datetime.now().isoformat(),
            "level": level,
            "message": message,
            "service": service,
            "host": host,
            "tags": tags or []
        }
        self.es.index(index=self.index_name, body=log_entry)
    
    def search_logs(self, query, size=100):
        search_body = {
            "query": {
                "multi_match": {
                    "query": query,
                    "type": "best_fields",
                    "fields": ["message", "service", "host", "tags"]
                }
            },
            "sort": [{"timestamp": {"order": "desc"}}],
            "size": size
        }
        response = self.es.search(index=self.index_name, body=search_body)
        return [hit["_source"] for hit in response["hits"]["hits"]]

class SearchEngine:
    def __init__(self, es_host="localhost", es_port=9200):
        self.es = Elasticsearch([f"{es_host}:{es_port}"])
        self.index_name = "documents"
        self._create_index()
    
    def _create_index(self):
        if not self.es.indices.exists(index=self.index_name):
            mapping = {
                "mappings": {
                    "properties": {
                        "title": {"type": "text"},
                        "content": {"type": "text"},
                        "category": {"type": "keyword"},
                        "tags": {"type": "keyword"},
                        "created_at": {"type": "date"}
                    }
                }
            }
            self.es.indices.create(index=self.index_name, body=mapping)
    
    def index_document(self, title, content, category="general", tags=None):
        document = {
            "title": title,
            "content": content,
            "category": category,
            "tags": tags or [],
            "created_at": datetime.now().isoformat()
        }
        self.es.index(index=self.index_name, body=document)
    
    def search_documents(self, query, size=100):
        search_body = {
            "query": {
                "multi_match": {
                    "query": query,
                    "type": "best_fields",
                    "fields": ["title", "content", "category", "tags"]
                }
            },
            "sort": [{"created_at": {"order": "desc"}}],
            "size": size
        }
        response = self.es.search(index=self.index_name, body=search_body)
        return [hit["_source"] for hit in response["hits"]["hits"]]

